function(expected){
  function t(v){ return String(v == null ? '' : v).replace(/\s+/g,' ').trim(); }
  function visible(el){
    if(!el) return false;
    const st = window.getComputedStyle(el);
    if(!st) return false;
    if(st.display==='none' || st.visibility==='hidden' || Number(st.opacity||'1')<=0.02) return false;
    const r = el.getBoundingClientRect();
    return r.width>2 && r.height>2;
  }
  const cands = Array.from(document.querySelectorAll('textarea,[contenteditable="true"],[role="textbox"]')).filter(visible);
  let best = null;
  let text = '';
  for(const el of cands){
    const v = t(el.value != null ? el.value : (el.innerText || el.textContent || ''));
    if(v.length > text.length){ text = v; best = el; }
  }
  const expTitle = t(expected && expected.title);
  const expSubtitle = t(expected && expected.subtitle);
  const expContent = t(expected && expected.content);
  const hasTitle = !expTitle || text.includes(expTitle);
  const hasSubtitle = !expSubtitle || text.includes(expSubtitle);
  const hasContent = !expContent || text.includes(expContent);
  const ok = !!text && hasTitle && hasSubtitle && hasContent;
  return {
    ok,
    text,
    textLen: text.length,
    hasTitle,
    hasSubtitle,
    hasContent,
    missing: [hasTitle ? '' : 'title', hasSubtitle ? '' : 'subtitle', hasContent ? '' : 'content'].filter(Boolean),
    tag: best ? String(best.tagName||'').toLowerCase() : '',
    role: best ? String(best.getAttribute('role')||'') : ''
  };
}
